const taskDescription = $json.task?.description || $json.description || '';
const existingFiles = $json.existing_files || [];
const existingFilesSection = existingFiles.length > 0
  ? '

EXISTING PROJECT FILES (modify or extend these rather than rewriting from scratch):
' +
    existingFiles.map(f => `### ${f.path}
\`\`\`
${f.content}
\`\`\``).join('

')
  : '';
return [{
  json: {
    model: 'local-model',
    messages: [{
      role: 'user',
      content: `You are a Senior Full-Stack Developer. Output ONLY code files, no explanations.

Tech Stack: TypeScript, Node.js/Express, React/Vite, PostgreSQL/Prisma

Security: JWT auth, bcrypt passwords, rate limiting, validated inputs, CORS

For EACH file output EXACTLY this format:
### path/to/file.ts
\`\`\`ts
[complete file content]
\`\`\`

No other text. No numbered lists. No explanations. Just the file blocks.${existingFilesSection}

Task: ${taskDescription}`
    }],
    temperature: 0.7,
    top_p: 0.8,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 1.5,
    max_tokens: 4096
  }
}];

const raw = $json.choices[0].message.content || '';
// Strip thinking - handle both <think>...</think> and bare text ending with </think>
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) {
  content = content.split('</think>').pop().trim();
}
const files = [];
const seen = new Set();
const re = /###\s+((?:[\w.-]+\/)*[\w.-]+\.(?:ts|tsx|js|jsx|json|md|yml|yaml|env|prisma|css|html|sh|Dockerfile|gitignore))\s*\n```[\w]*\n([\s\S]*?)```/g;
let m;
while ((m = re.exec(content)) !== null) {
  const path = m[1].trim();
  const fileContent = m[2];
  if (path && !seen.has(path) && fileContent.trim().length > 20) {
    seen.add(path);
    files.push({ path, content: fileContent });
  }
}
return [{ json: { files } }];
